  }, "\uD30C\uD2B8\uB108\uC2ED(Partnership): \uD611\uC5C5 \uAD00\uACC4\uC774\uB2E4. \uAC01 \uCEE8\uD14D\uC2A4\uD2B8\uC5D0\uC11C\uB294 \uC591\uCE21 \uC2DC\uC2A4\uD15C \uBAA8\uB450\uC758 \uAC1C\uBC1C \uC694\uAD6C\uB97C \uC218\uC6A9\uD560 \uC218 \uC788\uB294 \uC778\uD130\uD398\uC774\uC2A4\uB97C \uB9CC\uB4E4\uC5B4 \uB098\uAC00\uAE30 \uC704\uD574 \uBC18\uB4DC\uC2DC \uD611\uB825\uD55C\uB2E4.\n\uC0C1\uD638 \uC758\uC874\uC801\uC778 \uAE30\uB2A5\uC740 \uBC18\uB4DC\uC2DC \uC77C\uC815\uC744 \uC138\uC6CC \uAC19\uC740 \uB9B4\uB9AC\uC2A4\uC5D0\uC11C \uC644\uC131\uD560 \uC218 \uC788\uB3C4\uB85D \uD55C\uB2E4.")), mdx("li", {
